                  ) : (
                    <>
                      Send My Free Guide
                      <ArrowRight size={16} strokeWidth={2.5} />
                    </>
                  )}
                </button>

                {/* API error */}
                {status === 'error' && (
                  <div role="alert" style={{
                    display: 'flex', alignItems: 'center', gap: 8,
                    background: 'rgba(192,57,43,.06)', border: '1px solid rgba(192,57,43,.2)',
                    borderRadius: 10, padding: '10px 14px',
