import { createContext, useContext, useState, useEffect } from 'react';
import api from '../api';

// Create the Context
const CartContext = createContext();

// Create a custom hook so we can easily use the cart anywhere
export const useCart = () => {
  return useContext(CartContext);
};

export const CartProvider = ({ children }) => {
  // 1. Initialize cart and franchise data from localStorage
  const [cartItems, setCartItems] = useState(() => {
    const savedCart = localStorage.getItem('fohow_cart');
    return savedCart ? JSON.parse(savedCart) : [];
  });

  const [franchiseId, setFranchiseId] = useState(() => {
    return localStorage.getItem('fohow_franchise') || '';
  });

  const [discountRate, setDiscountRate] = useState(() => {
    return Number(localStorage.getItem('fohow_discount')) || 0;
  });

  // 2. Global business settings (fetched from backend)
  const [globalSettings, setGlobalSettings] = useState({
    home_delivery_fee: 500,
    pickup_delivery_fee: 200,
    franchise_discount_rate: 20
  });

  useEffect(() => {
    const loadBusinessSettings = async () => {
      try {
        const res = await api.get('/settings');
        if (res.data && res.data.home_delivery_fee) setGlobalSettings(res.data);
      } catch (err) {
        console.log('Using default fallback fees.');
      }
    };
    loadBusinessSettings();
  }, []);

  // 3. Sync cart/franchise to localStorage whenever state changes
  useEffect(() => {
    localStorage.setItem('fohow_cart', JSON.stringify(cartItems));
    localStorage.setItem('fohow_franchise', franchiseId);
    localStorage.setItem('fohow_discount', discountRate.toString());
  }, [cartItems, franchiseId, discountRate]);

  // 3. Cart Operations
  const addToCart = (product, quantity = 1) => {
    setCartItems((prevItems) => {
      const existingItem = prevItems.find((item) => item.id === product.id);
      if (existingItem) {
        return prevItems.map((item) =>
          item.id === product.id
            ? { ...item, quantity: item.quantity + quantity }
            : item
        );
      }
      return [...prevItems, { ...product, quantity }];
    });
  };

  const removeFromCart = (productId) => {
    setCartItems((prevItems) => prevItems.filter((item) => item.id !== productId));
  };

  // Fixed: Added updateQuantity so the +/- buttons on Checkout/Product Detail work!
  const updateQuantity = (productId, newQuantity) => {
    if (newQuantity < 1) return; // Prevent going below 1 via this function
    setCartItems((prevItems) =>
      prevItems.map((item) =>
        item.id === productId ? { ...item, quantity: newQuantity } : item
      )
    );
  };

  const clearCart = () => {
    setCartItems([]);
  };

  // 4. Franchise Discount Logic — uses live rate from backend
  const applyFranchise = (id) => {
    if (id && id.trim().length >= 4) {
      setFranchiseId(id.trim().toUpperCase());
      // Convert percentage (e.g. 20) to decimal (0.20)
      setDiscountRate(globalSettings.franchise_discount_rate / 100);
      return true;
    }
    return false;
  };

  const removeFranchise = () => {
    setFranchiseId('');
    setDiscountRate(0); // Reset back to retail price
  };

  // 5. Calculate Advanced Totals
  const cartCount = cartItems.reduce((count, item) => count + item.quantity, 0);
  
  // Retail Total
  const cartSubtotal = cartItems.reduce((total, item) => total + (Number(item.price_kes) * item.quantity), 0);
  
  // Amount Saved
  const cartDiscount = cartSubtotal * discountRate;
  
  // 🔵 16% VAT Calculation (Kenyan Standard) 🔵
  const cartTax = (cartSubtotal - cartDiscount) * 0.16;
  
  // Final Charge (Including VAT)
  const cartTotal = (cartSubtotal - cartDiscount) + cartTax;


  return (
    <CartContext.Provider 
      value={{ 
        cartItems, 
        addToCart, 
        removeFromCart, 
        updateQuantity, 
        clearCart, 
        cartCount,
        cartSubtotal,
        cartDiscount,
        cartTax,      // ← Exposed for VAT breakdown
        cartTotal,
        franchiseId,

        discountRate,
        applyFranchise,
        removeFranchise,
        globalSettings,   // ← exposed for Checkout & elsewhere
      }}
    >
      {children}
    </CartContext.Provider>
  );
};

import { createContext, useState, useEffect, useContext } from 'react';
import api from '../api';

const SettingsContext = createContext();

export const useSettings = () => useContext(SettingsContext);

export const SettingsProvider = ({ children }) => {
  const [globalDiscount, setGlobalDiscount] = useState(20); // Default to 20%
  const [deliveryFees, setDeliveryFees] = useState({ home: 500, pickup: 200 });
  const [loading, setLoading] = useState(true);

  const fetchSettings = async () => {
    try {
      const response = await api.get('/settings');
      if (response.data) {
        // Map backend 'franchise_discount_rate' to 'globalDiscount' for the UI
        if (response.data.franchise_discount_rate !== undefined) {
          setGlobalDiscount(response.data.franchise_discount_rate);
        }
        if (response.data.home_delivery_fee !== undefined) {
          setDeliveryFees({
            home: response.data.home_delivery_fee,
            pickup: response.data.pickup_delivery_fee
          });
        }
      }
    } catch (error) {
      console.error("Failed to fetch global settings:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSettings();
  }, []);

  // Admin function to update state locally after a successful API call
  const updateLocalDiscount = (newVal) => setGlobalDiscount(newVal);
  const updateLocalDeliveryFees = (newFees) => setDeliveryFees(newFees);

  return (
    <SettingsContext.Provider value={{ 
      globalDiscount, 
      deliveryFees,
      updateLocalDiscount, 
      updateLocalDeliveryFees,
      loading, 
      refreshSettings: fetchSettings 
    }}>
      {children}
    </SettingsContext.Provider>
  );
};

import { useState, useEffect, useRef } from 'react';
import { Calendar, User, ArrowLeft, ArrowRight, BookOpen } from 'lucide-react';
import api from '../api';

/* ── robust fade-up hook ── */
const useInView = (threshold = 0.08) => {
  const [visible, setVisible] = useState(false);
  const [element, setElement] = useState(null);

  useEffect(() => {
    if (!element) return;
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setVisible(true); obs.disconnect(); }
    }, { threshold });
    obs.observe(element);
    return () => obs.disconnect();
  }, [element, threshold]);

  return [setElement, visible];
};

const Blog = () => {
  const [blogs, setBlogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeArticle, setActiveArticle] = useState(null);

  const [headerRef, headerVisible] = useInView(0.05);
  const [gridRef, gridVisible] = useInView(0.04);

  useEffect(() => {
    const fetchBlogs = async () => {
      setLoading(true);
      try {
        const response = await api.get('/blogs');
        if (response.data) {
          // ONLY show articles that the admin has marked as 'Published'
          const publishedBlogs = response.data.filter(blog => blog.is_published);
          setBlogs(publishedBlogs);
        }
      } catch (error) {
        console.error("Error fetching blogs:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBlogs();
  }, []);

  // ══════════════════════════════════
  //  FULL ARTICLE VIEW
  // ══════════════════════════════════
