          <div className="prose prose-lg max-w-none text-[#5a5648] font-light leading-[1.85] whitespace-pre-wrap selection:bg-[#811816] selection:text-[#f7f4ef]">
            {activeArticle.content}
          </div>

        </div>
      </div>
    );
  }

  // ══════════════════════════════════
  //  BLOG LIST VIEW (THE JOURNAL)
  // ══════════════════════════════════
