        ) : (
          /* AUTO-FIT GRID: Stretches items to fill white space! */
          <div className="grid grid-cols-[repeat(auto-fit,minmax(320px,1fr))] gap-6 md:gap-8">
            {blogs.map((blog, i) => (
              <div
                key={blog.id}
