import { useState, useEffect } from 'react';
import { Plus, Edit, Trash2, X, Image as ImageIcon, FileText } from 'lucide-react';
import api from '../../api';

const AdminBlog = () => {
  const [blogs, setBlogs] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);
  const [imageFile, setImageFile] = useState(null);
  
  const [formData, setFormData] = useState({
    title: '', excerpt: '', content: '', author: 'Fohow Eden Life', is_published: true
  });

  const fetchBlogs = async () => {
    setLoading(true);
    const response = await api.get('/blogs');
    if (response.data) setBlogs(response.data);
    setLoading(false);
  };

  useEffect(() => { fetchBlogs(); }, []);

  const handleDelete = async (id, title) => {
    if (window.confirm(`Permanently delete article: "${title}"?`)) {
      const response = await api.delete(`/blogs/${id}`);
      if (response.ok) fetchBlogs();
    }
  };

  const openModal = (blog = null) => {
    if (blog) {
      setIsEditing(true);
      setEditId(blog.id);
      setFormData({
        title: blog.title, excerpt: blog.excerpt || '', content: blog.content, 
        author: blog.author || 'Fohow Eden Life', is_published: blog.is_published
      });
    } else {
      setIsEditing(false);
      setEditId(null);
      setFormData({ title: '', excerpt: '', content: '', author: 'Fohow Eden Life', is_published: true });
    }
    setImageFile(null);
    setIsModalOpen(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const data = new FormData();
    Object.keys(formData).forEach(key => data.append(key, formData[key]));
    if (imageFile) data.append('image', imageFile);

    const response = isEditing 
      ? await api.sendForm(`/blogs/${editId}`, 'PUT', data)
      : await api.sendForm('/blogs', 'POST', data);

    if (response.ok) {
      fetchBlogs();
      setIsModalOpen(false);
    } else {
      alert("Error saving blog post.");
    }
  };

  return (
    <div className="p-8 lg:p-12 relative bg-[#fcfbf9] min-h-screen font-dm">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h1 className="font-garamond text-3xl font-medium text-stone-900">Blog Posts</h1>
          <p className="mt-1 text-sm text-stone-500">Manage articles and TCM education.</p>
        </div>
        <button onClick={() => openModal()} className="flex items-center px-5 py-2.5 text-sm font-medium text-[#f7f4ef] bg-[#811816] rounded-lg shadow-sm hover:bg-[#6a1210] hover:shadow-md transition-all duration-300">
          <Plus className="w-4 h-4 mr-2" /> Write Article
        </button>
      </div>

      <div className="bg-white border border-stone-200 rounded-2xl overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-stone-50 text-stone-500 text-sm border-b border-stone-200">
            <tr>
              <th className="px-6 py-4 font-medium">Image</th>
              <th className="px-6 py-4 font-medium">Title</th>
              <th className="px-6 py-4 font-medium">Date</th>
              <th className="px-6 py-4 font-medium">Status</th>
              <th className="px-6 py-4 font-medium text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-stone-100 text-sm">
            {loading ? <tr><td colSpan="5" className="py-8 text-center text-stone-500">Loading articles...</td></tr> : 
              blogs.length === 0 ? <tr><td colSpan="5" className="py-8 text-center text-stone-500">No blog posts yet.</td></tr> :
              blogs.map((blog) => (
                <tr key={blog.id} className="hover:bg-[#fcf5f5]/50 transition-colors">
                  <td className="px-6 py-4">
                    {blog.image_url ? 
                      <img src={api.getImageUrl(blog.image_url)} alt="cover" className="w-16 h-10 object-cover rounded shadow-sm border border-stone-100" /> : 
                      <div className="w-16 h-10 bg-stone-100 rounded flex items-center justify-center text-stone-400"><ImageIcon className="w-4 h-4"/></div>
                    }
                  </td>
                  <td className="px-6 py-4 font-medium text-stone-900">{blog.title}</td>
                  <td className="px-6 py-4 text-stone-500">{new Date(blog.created_at).toLocaleDateString()}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2.5 py-1 rounded-full text-xs font-bold border ${blog.is_published ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-amber-50 text-amber-700 border-amber-200'}`}>
                      {blog.is_published ? 'Published' : 'Draft'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => openModal(blog)} className="p-2 text-stone-400 hover:text-[#d2a356] transition-colors"><Edit className="w-4 h-4" /></button>
                    <button onClick={() => handleDelete(blog.id, blog.title)} className="p-2 text-stone-400 hover:text-red-600 transition-colors"><Trash2 className="w-4 h-4" /></button>
                  </td>
                </tr>
              ))
            }
          </tbody>
        </table>
      </div>

      {/* Editor Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-stone-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
            <div className="flex items-center justify-between px-6 py-4 border-b border-stone-100 bg-stone-50">
              <h2 className="text-xl font-bold text-stone-900 flex items-center"><FileText className="w-5 h-5 mr-2 text-[#811816]"/> {isEditing ? 'Edit Article' : 'New Article'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-stone-400 hover:text-[#811816] transition-colors"><X className="w-6 h-6"/></button>
            </div>
            
            <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto custom-scrollbar">
              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Article Title</label>
                <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all" />
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Cover Image</label>
                <input type="file" accept="image/*" onChange={e => setImageFile(e.target.files[0])} className="w-full text-sm file:mr-4 file:py-2.5 file:px-4 file:rounded-xl file:border-0 file:font-medium file:bg-[#fcf5f5] file:text-[#811816] hover:file:bg-[#811816]/10 cursor-pointer text-stone-500 transition-colors" />
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Short Excerpt (For preview cards)</label>
                <textarea rows="2" value={formData.excerpt} onChange={e => setFormData({...formData, excerpt: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all resize-none"></textarea>
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Full Article Content</label>
                <textarea required rows="12" value={formData.content} onChange={e => setFormData({...formData, content: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all resize-none"></textarea>
              </div>

              <div className="flex items-center gap-3 pt-5 border-t border-stone-100">
                <label className="flex items-center cursor-pointer group">
                  <input type="checkbox" checked={formData.is_published} onChange={e => setFormData({...formData, is_published: e.target.checked})} className="w-5 h-5 rounded border-stone-300 text-[#811816] focus:ring-[#811816] accent-[#811816] cursor-pointer" />
                  <span className="ml-2.5 font-medium text-stone-700 group-hover:text-stone-900 transition-colors">Publish immediately</span>
                </label>
                <div className="flex-1"></div>
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-5 py-2.5 font-medium text-stone-600 bg-stone-100 hover:bg-stone-200 rounded-xl transition-colors">Cancel</button>
                <button type="submit" className="px-5 py-2.5 font-medium text-[#f7f4ef] bg-[#811816] hover:bg-[#6a1210] hover:shadow-md rounded-xl transition-all duration-300">{isEditing ? 'Save Changes' : 'Publish Article'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminBlog;

import { useState, useEffect } from 'react';
import { Plus, Trash2, X, Calendar, MapPin, Clock, Users, Globe, Edit } from 'lucide-react';
import api from '../../api';

const AdminEvents = () => {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  
  const [formData, setFormData] = useState({
    title: '',
    category: 'Practitioner Training',
    event_date: '',
    event_month: '',
    event_time: '',
    location: '',
    description: '',
    spots_left: 'Unlimited',
    is_online: false,
    is_published: true
  });

  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);

  const fetchEvents = async () => {
    setLoading(true);
    try {
      const response = await api.get('/events');
      const eventsData = response.data?.data || response.data || [];
      setEvents(eventsData);
    } catch (err) {
      console.error('Failed to fetch events:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEvents();
  }, []);

  const handleEdit = (event) => {
    setIsEditing(true);
    setEditId(event.id);
    setFormData({
      title: event.title,
      category: event.category,
      event_date: event.event_date,
      event_month: event.event_month,
      event_time: event.event_time,
      location: event.location,
      description: event.description,
      spots_left: event.spots_left,
      is_online: event.is_online,
      is_published: event.is_published
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (id, title) => {
    if (window.confirm(`Permanently delete event: "${title}"?`)) {
      try {
        await api.delete(`/events/${id}`);
        fetchEvents();
      } catch (err) {
        alert("Error deleting event.");
      }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (isEditing) {
        response = await api.put(`/events/${editId}`, formData);
      } else {
        response = await api.post('/events', formData);
      }
      
      if (response.data?.success || response.status === 201 || response.status === 200) {
        fetchEvents();
        setIsModalOpen(false);
        setIsEditing(false);
        setEditId(null);
        setFormData({
          title: '',
          category: 'Practitioner Training',
          event_date: '',
          event_month: '',
          event_time: '',
          location: '',
          description: '',
          spots_left: 'Unlimited',
          is_online: false,
          is_published: true
        });
      }
    } catch (err) {
      alert("Error saving event.");
    }
  };

  const openNewModal = () => {
    setIsEditing(false);
    setEditId(null);
    setFormData({
      title: '',
      category: 'Practitioner Training',
      event_date: '',
      event_month: '',
      event_time: '',
      location: '',
      description: '',
      spots_left: 'Unlimited',
      is_online: false,
      is_published: true
    });
    setIsModalOpen(true);
  };

  return (
    <div className="p-8 lg:p-12 relative bg-[#fcfbf9] min-h-screen font-dm">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h1 className="font-garamond text-3xl font-medium text-stone-900">Upcoming Seminars</h1>
          <p className="mt-1 text-sm text-stone-500">Manage educational events and training certifications.</p>
        </div>
        <button 
          onClick={openNewModal} 
          className="flex items-center px-5 py-2.5 text-sm font-medium text-[#f7f4ef] bg-[#811816] rounded-lg shadow-sm hover:bg-[#6a1210] hover:shadow-md transition-all duration-300"
        >
          <Plus className="w-4 h-4 mr-2" /> Add New Event
        </button>
      </div>

      <div className="bg-white border border-stone-200 rounded-2xl overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-stone-50 text-stone-500 text-sm border-b border-stone-200">
            <tr>
              <th className="px-6 py-4 font-medium">Date</th>
              <th className="px-6 py-4 font-medium">Event Title</th>
              <th className="px-6 py-4 font-medium">Status</th>
              <th className="px-6 py-4 font-medium">Location</th>
              <th className="px-6 py-4 font-medium text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-stone-100 text-sm">
            {loading ? (
              <tr><td colSpan="5" className="py-8 text-center text-stone-500">Loading events...</td></tr>
            ) : events.length === 0 ? (
              <tr><td colSpan="5" className="py-8 text-center text-stone-500">No upcoming events scheduled.</td></tr>
            ) : (
              events.map((event) => (
                <tr key={event.id} className="hover:bg-[#fcf5f5]/50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-[#811816]">{event.event_month}</span>
                      <span className="text-lg font-garamond">{event.event_date}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-stone-900">{event.title}</div>
                    <div className="text-xs text-stone-500 flex items-center gap-1.5 mt-1">
                      <Clock size={12} /> {event.event_time}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-1.5">
                      <span className="inline-flex w-fit px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider bg-[#fdf8ef] text-[#d2a356] border border-[#d2a356]/30">
                        {event.category}
                      </span>
                      <span className={`inline-flex w-fit px-2 py-0.5 rounded-full text-[9px] font-bold uppercase ${event.is_published ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-amber-50 text-amber-700 border border-amber-100'}`}>
                        {event.is_published ? 'Published' : 'Draft'}
                      </span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-stone-600 flex items-center gap-1.5">
                      {event.is_online ? <Globe size={14} className="text-blue-500" /> : <MapPin size={14} className="text-stone-400" />}
                      {event.location}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => handleEdit(event)} 
                      className="p-2 text-stone-400 hover:text-[#d2a356] transition-colors"
                    >
                      <Edit className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => handleDelete(event.id, event.title)} 
                      className="p-2 text-stone-400 hover:text-red-600 transition-colors"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Event Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-stone-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
            <div className="flex items-center justify-between px-6 py-4 border-b border-stone-100 bg-stone-50">
              <h2 className="text-xl font-bold text-stone-900 flex items-center">
                <Calendar className="w-5 h-5 mr-2 text-[#811816]"/> {isEditing ? 'Edit Event' : 'Create New Event'}
              </h2>
              <button onClick={() => setIsModalOpen(false)} className="text-stone-400 hover:text-[#811816] transition-colors">
                <X className="w-6 h-6"/>
              </button>
            </div>
            
            <form onSubmit={handleSubmit} className="p-6 space-y-4 overflow-y-auto custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="md:col-span-2">
                  <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Event Title</label>
                  <input 
                    required 
                    type="text" 
                    value={formData.title} 
                    onChange={e => setFormData({...formData, title: e.target.value})} 
                    placeholder="e.g. TCM Meridian Therapy Certification"
                    className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all" 
                  />
                </div>

                <div>
                  <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Category</label>
                  <select 
                    value={formData.category} 
                    onChange={e => setFormData({...formData, category: e.target.value})}
                    className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all appearance-none bg-white"
                  >
                    <option>Practitioner Training</option>
                    <option>Product Seminar</option>
                    <option>B2B Webinar</option>
                    <option>Health Workshop</option>
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Spots Remaining</label>
                  <input 
                    type="text" 
                    value={formData.spots_left} 
                    onChange={e => setFormData({...formData, spots_left: e.target.value})} 
                    placeholder="e.g. 8 or Unlimited"
                    className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all" 
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Day (DD)</label>
                    <input 
                      required 
                      type="text" 
                      value={formData.event_date} 
                      onChange={e => setFormData({...formData, event_date: e.target.value})} 
                      placeholder="15"
                      className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all text-center" 
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Month (MMM)</label>
                    <input 
                      required 
                      type="text" 
                      value={formData.event_month} 
                      onChange={e => setFormData({...formData, event_month: e.target.value})} 
                      placeholder="OCT"
                      className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all text-center" 
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Time Range</label>
                  <input 
                    required 
                    type="text" 
                    value={formData.event_time} 
                    onChange={e => setFormData({...formData, event_time: e.target.value})} 
                    placeholder="09:00 AM - 04:00 PM"
                    className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all" 
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Location</label>
                  <input 
                    required 
                    type="text" 
                    value={formData.location} 
                    onChange={e => setFormData({...formData, location: e.target.value})} 
                    placeholder="e.g. Cargen House, Nairobi or Zoom Link"
                    className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all" 
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-xs font-bold text-stone-500 uppercase tracking-widest mb-1.5">Description</label>
                  <textarea 
                    rows="3" 
                    value={formData.description} 
                    onChange={e => setFormData({...formData, description: e.target.value})} 
                    className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none transition-all resize-none"
                  ></textarea>
                </div>

                <div className="md:col-span-2 flex flex-col gap-3">
                  <label className="flex items-center cursor-pointer group">
                    <input 
                      type="checkbox" 
                      checked={formData.is_online} 
                      onChange={e => setFormData({...formData, is_online: e.target.checked})} 
                      className="w-5 h-5 rounded border-stone-300 text-[#811816] focus:ring-[#811816] accent-[#811816] cursor-pointer" 
                    />
                    <span className="ml-2.5 font-medium text-stone-700 group-hover:text-stone-900 transition-colors">This is a virtual/online event</span>
                  </label>
                  
                  <label className="flex items-center cursor-pointer group">
                    <input 
                      type="checkbox" 
                      checked={formData.is_published} 
                      onChange={e => setFormData({...formData, is_published: e.target.checked})} 
                      className="w-5 h-5 rounded border-stone-300 text-[#811816] focus:ring-[#811816] accent-[#811816] cursor-pointer" 
                    />
                    <span className="ml-2.5 font-medium text-stone-700 group-hover:text-stone-900 transition-colors">Publish immediately (Live on Storefront)</span>
                  </label>
                </div>
              </div>

              <div className="flex items-center gap-3 pt-5 border-t border-stone-100">
                <div className="flex-1"></div>
                <button 
                  type="button" 
                  onClick={() => setIsModalOpen(false)} 
                  className="px-5 py-2.5 font-medium text-stone-600 bg-stone-100 hover:bg-stone-200 rounded-xl transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="px-8 py-2.5 font-medium text-[#f7f4ef] bg-[#811816] hover:bg-[#6a1210] hover:shadow-md rounded-xl transition-all duration-300"
                >
                  {isEditing ? 'Save Changes' : 'Publish Event'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminEvents;

import { useState, useEffect } from 'react';
import { Tag, Plus, ShieldCheck, X } from 'lucide-react';
import api from '../../api';

const AdminFranchises = () => {
  const [franchises, setFranchises] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({ code: '', discount_rate: 20 });

  const fetchFranchises = async () => {
    try {
      const response = await api.get('/franchises'); 
      if (response.data) setFranchises(response.data);
    } catch (err) {
      console.error("Failed to fetch franchises", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchFranchises(); }, []);

  const handleToggleActive = async (id, currentStatus) => {
    try {
      await api.put(`/franchises/${id}`, { is_active: !currentStatus });
      setFranchises(franchises.map(f => f.id === id ? { ...f, is_active: !currentStatus } : f));
    } catch (err) {
      alert("Failed to update franchise status.");
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      // Convert percentage to decimal for database (e.g. 20 -> 0.20)
      const payload = { 
        code: formData.code.toUpperCase(), 
        discount_rate: formData.discount_rate / 100 
      };
      const response = await api.post('/franchises', payload);
      if (response.ok) {
        fetchFranchises();
        setIsModalOpen(false);
        setFormData({ code: '', discount_rate: 20 });
      }
    } catch (err) {
      alert("Error creating Franchise ID. It might already exist.");
    }
  };

  return (
    <div className="p-8 lg:p-12 bg-[#fcfbf9] min-h-screen font-dm">
      <div className="flex items-center justify-between mb-10">
        <div>
          <h1 className="font-garamond text-3xl font-medium text-stone-900">Franchise IDs</h1>
          <p className="mt-1 text-sm text-stone-500">Manage B2B discount codes for clinic owners.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)} 
