              </div>
              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Discount Rate (%)</label>
                <div className="relative">
                  <input required type="number" value={formData.discount_rate} onChange={e => setFormData({...formData, discount_rate: Number(e.target.value)})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none font-bold text-stone-900" />
                  <span className="absolute right-4 top-1/2 -translate-y-1/2 text-stone-400 font-bold">%</span>
