import { useState, useEffect } from 'react';
import { Smartphone, Calendar, MessageCircle, UserPlus } from 'lucide-react';
import api from '../../api';

const AdminLeads = () => {
  const [leads, setLeads] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchLeads = async () => {
      try {
        const response = await api.get('/leads'); 
        if (response.data) setLeads(response.data);
      } catch (err) {
        console.error("Failed to fetch leads", err);
      } finally {
        setLoading(false);
      }
    };
    fetchLeads();
  }, []);

  const handleStatusChange = async (id, newStatus) => {
    try {
      await api.put(`/leads/${id}/status`, { status: newStatus });
      setLeads(leads.map(lead => lead.id === id ? { ...lead, status: newStatus } : lead));
    } catch (err) {
      alert("Failed to update status.");
    }
  };

  return (
    <div className="p-8 lg:p-12 bg-[#fcfbf9] min-h-screen font-dm">
      <div className="flex items-center justify-between mb-10">
        <div>
          <h1 className="font-garamond text-3xl font-medium text-stone-900">WhatsApp Leads</h1>
          <p className="mt-1 text-sm text-stone-500">Captured numbers from the Exit-Intent Pop-up.</p>
        </div>
        <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-stone-200 shadow-sm">
          <UserPlus className="w-5 h-5 text-[#811816]" />
          <span className="font-bold text-stone-900">{leads.length} Total Leads</span>
        </div>
      </div>

      <div className="bg-white border shadow-sm border-stone-200 rounded-3xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left whitespace-nowrap">
            <thead className="bg-stone-50 text-stone-500 text-sm border-b border-stone-200">
              <tr>
                <th className="px-6 py-4 font-medium">WhatsApp Number</th>
                <th className="px-6 py-4 font-medium">Source</th>
                <th className="px-6 py-4 font-medium">Captured On</th>
                <th className="px-6 py-4 font-medium">Status</th>
                <th className="px-6 py-4 font-medium text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-stone-100 text-sm">
              {loading ? (
                <tr><td colSpan="5" className="py-10 text-center text-stone-500">Loading leads...</td></tr>
              ) : leads.length === 0 ? (
                <tr><td colSpan="5" className="py-10 text-center text-stone-500">No leads captured yet.</td></tr>
              ) : (
                leads.map((lead) => (
                  <tr key={lead.id} className="transition-colors hover:bg-[#fcf5f5]/50">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-[#e8f0ea] flex items-center justify-center border border-[#4a7c59]/20">
                          <Smartphone className="w-5 h-5 text-[#4a7c59]" />
                        </div>
                        <span className="font-bold text-stone-900 text-base">{lead.phone}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-stone-600 font-medium">{lead.source || 'Exit-Intent Popup'}</td>
                    <td className="px-6 py-4 text-stone-500">
                      <div className="flex items-center gap-1.5">
                        <Calendar className="w-4 h-4" />
                        {new Date(lead.created_at).toLocaleDateString()}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <select 
                        value={lead.status}
                        onChange={(e) => handleStatusChange(lead.id, e.target.value)}
                        className={`text-xs font-bold px-3 py-1.5 rounded-full border-2 cursor-pointer focus:outline-none transition-colors appearance-none text-center ${
                          lead.status === 'Converted' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 
                          lead.status === 'Contacted' ? 'bg-blue-50 text-blue-700 border-blue-200' : 
                          'bg-[#fdf8ef] text-[#d2a356] border-[#d2a356]/30'
                        }`}
                      >
                        <option value="New">New</option>
                        <option value="Contacted">Contacted</option>
                        <option value="Converted">Converted</option>
                      </select>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <a 
                        href={`https://wa.me/${lead.phone.replace(/[^0-9]/g, '')}?text=Hello!%20Here%20is%20the%20Fohow%20Clinical%20Guide%20you%20requested:`} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="inline-flex items-center px-4 py-2 bg-[#f0ece3] text-[#1c1a16] hover:bg-[#811816] hover:text-[#f7f4ef] rounded-lg transition-colors font-medium text-xs"
                      >
                        <MessageCircle className="w-4 h-4 mr-1.5" />
                        Message
                      </a>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminLeads;

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Lock, User, ArrowRight, ShieldAlert } from 'lucide-react';
import api from '../../api';

const AdminLogin = () => {
  const [formData, setFormData] = useState({ username: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await api.post('/auth/admin/login', formData);
      if (response.data && response.data.token) {
        localStorage.setItem('fohow_admin_token', response.data.token);
        localStorage.setItem('fohow_admin_role', response.data.role); // <-- Capture role!
        
        // Role-based redirection:
        if (response.data.role === 'boss') {
          navigate('/admin');
        } else {
          navigate('/admin/products');
        }
      } else {
        setError('Invalid credentials for Admin access.');
      }
    } catch (err) {
      setError('Access denied. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#1a0504] flex items-center justify-center px-6 font-dm">
      {/* Background Decorative Elements */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-10%] right-[-10%] w-[50vw] aspect-square rounded-full bg-[#811816] opacity-10 blur-[120px]" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[40vw] aspect-square rounded-full bg-[#d2a356] opacity-5 blur-[100px]" />
      </div>

      <div className="w-full max-w-md z-10">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-20 h-20 rounded-3xl bg-[#811816]/20 border border-[#d2a356]/30 mb-6">
            <span className="font-garamond text-3xl font-bold text-[#d2a356]">F</span>
          </div>
          <h1 className="font-garamond text-3xl font-medium text-[#f7f4ef]">Admin Command Center</h1>
          <p className="text-[#e8d5d5] opacity-60 text-sm mt-2">Authorized Access Only</p>
        </div>

        <div className="bg-white/5 backdrop-blur-xl border border-[#811816]/30 p-8 md:p-10 rounded-[2.5rem] shadow-2xl">
          <form onSubmit={handleSubmit} className="space-y-6">

            {error && (
              <div className="flex items-center gap-3 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm">
                <ShieldAlert size={18} />
                {error}
              </div>
            )}

            <div>
              <label className="block text-[0.75rem] font-bold text-[#d2a356] uppercase tracking-[0.15em] mb-2 ml-1">
                Username
              </label>
              <div className="relative group">
                <User
                  className="absolute left-4 top-1/2 -translate-y-1/2 text-[#a0998e] group-focus-within:text-[#d2a356] transition-colors"
                  size={18}
                />
                <input
                  id="admin-username"
                  type="text"
                  required
                  autoComplete="username"
                  value={formData.username}
                  onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                  className="w-full bg-white/10 border border-[#811816]/40 rounded-2xl py-4 pl-12 pr-4 text-[#f7f4ef] outline-none focus:border-[#d2a356] focus:ring-4 focus:ring-[#d2a356]/10 transition-all placeholder:text-stone-600"
                  placeholder="Enter admin username"
                />
              </div>
            </div>

            <div>
              <label className="block text-[0.75rem] font-bold text-[#d2a356] uppercase tracking-[0.15em] mb-2 ml-1">
                Secure Password
              </label>
              <div className="relative group">
                <Lock
                  className="absolute left-4 top-1/2 -translate-y-1/2 text-[#a0998e] group-focus-within:text-[#d2a356] transition-colors"
                  size={18}
                />
                <input
                  id="admin-password"
                  type="password"
                  autoComplete="off"
                  required
                  value={formData.password}
                  onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                  className="w-full bg-white/10 border border-[#811816]/40 rounded-2xl py-4 pl-12 pr-4 text-[#f7f4ef] outline-none focus:border-[#d2a356] focus:ring-4 focus:ring-[#d2a356]/10 transition-all placeholder:text-stone-600"
                  placeholder="••••••••"
                />
              </div>
            </div>

            <button
              id="admin-login-btn"
              type="submit"
              disabled={loading}
              className="w-full flex items-center justify-center gap-2 bg-[#d2a356] hover:bg-[#e0b772] text-[#1a0504] py-4 rounded-2xl font-bold tracking-wide transition-all hover:shadow-[0_0_20px_rgba(210,163,86,0.4)] disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? 'Verifying...' : 'Enter Command Center'}
              {!loading && <ArrowRight size={18} />}
            </button>
          </form>
        </div>

        <p className="text-center mt-8 text-stone-600 text-xs font-light">
          System ID: FOHOW-HQ-NAIROBI
        </p>
      </div>
    </div>
  );
};

export default AdminLogin;

import { useState, useEffect } from 'react';
import { Truck, Tag, Save, RefreshCcw, ShieldCheck } from 'lucide-react';
import api from '../../api';

const AdminSettings = () => {
