            <label className="block text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Member Discount Rate (%)</label>
            <div className="relative">
              <input type="number" value={settings.franchise_discount_rate} onChange={e => setSettings({...settings, franchise_discount_rate: Number(e.target.value)})} className="w-full px-4 py-3 bg-[#faf8f4] border border-stone-200 rounded-xl focus:border-[#d2a356] outline-none font-bold" />
              <span className="absolute right-4 top-1/2 -translate-y-1/2 text-stone-400 font-bold">%</span>
