import { useState, useEffect } from 'react';
import { Search, Filter, Eye, X, Package, CreditCard, User, Truck, MapPin, Tag, Smartphone } from 'lucide-react';
import api from '../../api';

const AdminOrders = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // Advanced B2B Filters
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [franchiseFilter, setFranchiseFilter] = useState("All");

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [modalLoading, setModalLoading] = useState(false);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const response = await api.get('/orders');
      if (response.data) setOrders(response.data);
    } catch (error) {
      console.error("Failed to fetch orders", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchOrders(); }, []);

  const handleStatusChange = async (orderId, newStatus) => {
    try {
      const response = await api.put(`/orders/${orderId}/status`, { status: newStatus });
      if (response.data) {
        setOrders(orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
      }
    } catch (error) {
      alert("Failed to update order status.");
    }
  };

  const handleViewOrder = async (orderId) => {
    setIsModalOpen(true);
    setModalLoading(true);
    try {
      const response = await api.get(`/orders/${orderId}`);
      if (response.data) {
        setSelectedOrder(response.data);
      }
    } catch (error) {
      console.error("Failed to fetch order details", error);
    } finally {
      setModalLoading(false);
    }
  };

  const filteredOrders = orders.filter(o => {
    // 1. Search Logic
    const matchesSearch = 
      o.order_number.toLowerCase().includes(searchQuery.toLowerCase()) ||
      o.customer_phone.includes(searchQuery) ||
      (o.customer_name && o.customer_name.toLowerCase().includes(searchQuery.toLowerCase())) ||
      (o.mpesa_receipt && o.mpesa_receipt.toLowerCase().includes(searchQuery.toLowerCase())) ||
      (o.franchise_id && o.franchise_id.toLowerCase().includes(searchQuery.toLowerCase()));
    
    // 2. Status Logic (Fulfillment & M-Pesa)
    const matchesStatus = statusFilter === "All" || o.status === statusFilter;

    // 3. Franchise / B2B Logic
    const matchesFranchise = 
      franchiseFilter === "All" || 
      (franchiseFilter === "Franchise" && o.franchise_id) || 
      (franchiseFilter === "Retail" && !o.franchise_id);

    return matchesSearch && matchesStatus && matchesFranchise;
  });

  const getStatusColor = (status) => {
    switch(status) {
      case 'Delivered': return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case 'Shipped': return 'bg-blue-50 text-blue-700 border-blue-200';
      case 'Paid': return 'bg-[#fdf8ef] text-[#d2a356] border-[#d2a356]/30';
      case 'Processing': return 'bg-purple-50 text-purple-700 border-purple-200';
      case 'Pending Payment': return 'bg-amber-50 text-amber-700 border-amber-200';
      case 'Cancelled': return 'bg-red-50 text-red-700 border-red-200';
      default: return 'bg-stone-50 text-stone-600 border-stone-200';
    }
  };

  const getParsedAddress = (addressData) => {
    if (!addressData) return {};
    if (typeof addressData === 'object') return addressData;
    try { return JSON.parse(addressData); } catch (e) { return {}; }
  };

  return (
    <div className="p-8 lg:p-12 relative bg-[#fcfbf9] min-h-screen font-dm">
      <div className="flex flex-col items-start justify-between gap-4 mb-8 sm:flex-row sm:items-center">
        <div>
          <h1 className="font-garamond text-3xl font-medium text-[#1c1a16]">Orders & Fulfillment</h1>
          <p className="mt-1 text-sm text-[#8a8070]">Track M-Pesa payments, manage B2B franchises, and fulfill logistics.</p>
        </div>
      </div>

      {/* ════════ TOOLBAR & FILTERS ════════ */}
      <div className="flex flex-col lg:flex-row items-center justify-between p-5 mb-8 bg-white border shadow-sm border-[#ede8df] rounded-2xl gap-4">
        
        {/* Search */}
        <div className="relative w-full lg:w-96">
          <Search className="absolute w-4 h-4 text-[#a0998e] left-4 top-3.5" />
          <input 
            type="text" 
            placeholder="Search Order, Phone, M-Pesa Ref, or Franchise ID..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full py-2.5 pl-11 pr-4 text-sm border rounded-xl bg-[#fcfbf9] border-[#ede8df] focus:outline-none focus:border-[#d2a356] focus:ring-1 focus:ring-[#d2a356] transition-colors"
          />
        </div>
        
        {/* Dropdown Filters */}
        <div className="flex flex-col sm:flex-row items-center gap-3 w-full lg:w-auto">
          
          {/* Status Filter */}
          <div className="relative w-full sm:w-auto flex items-center">
            <Filter className="absolute w-4 h-4 text-[#d2a356] left-3" />
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="w-full sm:w-48 py-2.5 pl-9 pr-4 text-sm border rounded-xl bg-[#fcfbf9] border-[#ede8df] focus:outline-none focus:border-[#d2a356] cursor-pointer appearance-none font-medium text-[#5a5648]"
            >
              <option value="All">All Statuses</option>
              <option value="Pending Payment">STK Pending</option>
              <option value="Paid">Paid (M-Pesa)</option>
              <option value="Processing">Processing</option>
              <option value="Shipped">Shipped</option>
              <option value="Delivered">Delivered</option>
              <option value="Cancelled">Cancelled</option>
            </select>
          </div>

          {/* Franchise Filter */}
          <div className="relative w-full sm:w-auto flex items-center">
            <Tag className="absolute w-4 h-4 text-[#d2a356] left-3" />
            <select 
              value={franchiseFilter}
              onChange={(e) => setFranchiseFilter(e.target.value)}
              className="w-full sm:w-48 py-2.5 pl-9 pr-4 text-sm border rounded-xl bg-[#fcfbf9] border-[#ede8df] focus:outline-none focus:border-[#d2a356] cursor-pointer appearance-none font-medium text-[#5a5648]"
            >
              <option value="All">All Buyers</option>
              <option value="Franchise">B2B Franchise</option>
              <option value="Retail">Standard Retail</option>
            </select>
          </div>
        </div>
      </div>

      {/* ════════ MAIN ORDERS TABLE ════════ */}
      <div className="overflow-hidden bg-white border shadow-sm border-[#ede8df] rounded-2xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="text-[0.75rem] bg-[#fcfbf9] text-[#8a8070] uppercase tracking-wider border-b border-[#ede8df]">
              <tr>
                <th className="px-6 py-4 font-bold">Order Details</th>
                <th className="px-6 py-4 font-bold">Customer & Type</th>
                <th className="px-6 py-4 font-bold">Items Purchased</th>
                <th className="px-6 py-4 font-bold">Total (KES)</th>
                <th className="px-6 py-4 font-bold">Fulfillment</th>
                <th className="px-6 py-4 font-bold text-right">Action</th>
              </tr>
            </thead>
            <tbody className="text-sm divide-y divide-[#ede8df]">
              {loading ? (
                <tr><td colSpan="6" className="py-12 text-center text-[#8a8070]">Loading Fohow Orders...</td></tr>
              ) : filteredOrders.length === 0 ? (
                <tr><td colSpan="6" className="py-12 text-center text-[#8a8070]">No orders match your filters.</td></tr>
              ) : (
                filteredOrders.map((order) => (
                  <tr key={order.id} className="transition-colors hover:bg-[#fdf8ef]/40">
                    
                    {/* Column 1: Order Meta */}
                    <td className="px-6 py-4">
                      <p className="font-bold text-[#1c1a16]">{order.order_number}</p>
                      <p className="text-xs text-[#8a8070] mt-1">{new Date(order.created_at).toLocaleString()}</p>
                    </td>

                    {/* Column 2: Customer, ID & Franchise */}
                    <td className="px-6 py-4">
                      <p className="font-medium text-[#1c1a16]">{order.customer_name || 'N/A'}</p>
                      <p className="text-xs text-[#5a5648] mt-0.5">{order.customer_phone}</p>
                      
                      {/* 🟢 NEW: ID Number Display */}
                      {order.customer_id_number && (
                        <p className="text-[0.65rem] font-bold text-[#8a8070] mt-0.5 uppercase tracking-wider">
                          ID: {order.customer_id_number}
                        </p>
                      )}

                      {order.franchise_id && (
                        <div className="mt-1.5 flex items-center gap-1 text-[0.65rem] font-bold text-[#d2a356] bg-[#fdf8ef] border border-[#d2a356]/30 px-2 py-0.5 rounded-md uppercase tracking-wider">
                          <Tag size={10} /> {order.franchise_id}
                        </div>
                      )}

                      {/* 🟢 NEW: Location Summary in Table */}
                      {order.delivery_address && (
                        <p className="text-[0.65rem] font-medium text-[#811816] mt-1 italic">
                           Map: {getParsedAddress(order.delivery_address).county}, {getParsedAddress(order.delivery_address).estate}
                        </p>
                      )}
                    </td>

                    {/* Column 3: The Product Names */}
                    <td className="px-6 py-4 max-w-[250px]">
                      <p className="text-sm text-[#1c1a16] font-medium truncate" title={order.product_names || "Products"}>
                        {order.product_names ? order.product_names : `${order.items_count} items`}
                      </p>
                      <p className="text-xs text-[#8a8070] mt-0.5">{order.items_count} Total Quantities</p>
                    </td>

                    {/* Column 4: Revenue & M-Pesa */}
                    <td className="px-6 py-4">
                      <p className="font-bold text-[#1c1a16]">{Number(order.total_amount).toLocaleString()}</p>
                      {order.mpesa_receipt ? (
                        <p className="text-[0.65rem] font-bold text-[#4a7c59] mt-1 uppercase tracking-wider flex items-center gap-1">
                          <Smartphone size={10}/> {order.mpesa_receipt}
                        </p>
                      ) : (
                        <p className="text-[0.65rem] font-bold text-amber-600 mt-1 uppercase tracking-wider">Unpaid / COD</p>
                      )}
                    </td>

                    {/* Column 5: Status Dropdown */}
                    <td className="px-6 py-4">
                      <select 
                        value={order.status}
                        onChange={(e) => handleStatusChange(order.id, e.target.value)}
                        className={`text-[0.7rem] uppercase tracking-wider font-bold px-3 py-1.5 rounded-md border cursor-pointer focus:outline-none transition-colors ${getStatusColor(order.status)}`}
                      >
                        <option value="Pending Payment">STK Pending</option>
                        <option value="Paid">Paid (M-Pesa)</option>
                        <option value="Processing">Processing</option>
                        <option value="Shipped">Shipped</option>
                        <option value="Delivered">Delivered</option>
                        <option value="Cancelled">Cancelled</option>
                      </select>
                    </td>

                    {/* Column 6: Action */}
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => handleViewOrder(order.id)}
                        className="p-2 transition-colors rounded-lg text-[#a0998e] hover:text-[#811816] hover:bg-[#fcf5f5]"
                      >
                        <Eye className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* ════════ VIEW ORDER MODAL ════════ */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-[#1a0504]/70 backdrop-blur-sm p-4">
          <div className="bg-[#fcfbf9] rounded-3xl w-full max-w-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            
            {/* Modal Header */}
            <div className="flex items-center justify-between px-8 py-6 border-b border-[#ede8df] bg-white">
              <div>
                <h2 className="text-2xl font-garamond font-medium text-[#1c1a16]">Order Summary</h2>
                {!modalLoading && selectedOrder && (
                  <p className="text-sm text-[#8a8070] mt-1 font-dm">ID: {selectedOrder.order_number}</p>
                )}
              </div>
              <button onClick={() => setIsModalOpen(false)} className="p-2 text-[#a0998e] hover:text-[#811816] rounded-full hover:bg-[#fcf5f5] transition">
                <X className="w-6 h-6"/>
              </button>
            </div>

            {/* Modal Body */}
            <div className="p-8 overflow-y-auto custom-scrollbar">
              {modalLoading || !selectedOrder ? (
                <div className="flex justify-center items-center h-48 text-[#d2a356] font-bold animate-pulse">Loading order details...</div>
              ) : (
                <div className="space-y-6">
                  
                  {/* Info Cards Row */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    
                    {/* Customer Card */}
                    <div className="p-4 border border-[#ede8df] bg-white rounded-2xl flex items-start gap-3 shadow-sm">
                      <User className="w-5 h-5 text-[#811816] mt-0.5 shrink-0" />
                      <div>
                        <p className="text-[0.65rem] font-bold text-[#a0998e] uppercase tracking-wider mb-1">Customer</p>
                        <p className="font-bold text-[#1c1a16]">{selectedOrder.customer_name || 'N/A'}</p>
                        <p className="text-sm text-[#5a5648] mt-0.5">{selectedOrder.customer_phone}</p>
                        
                        {/* 🟢 NEW: ID Number Display in Modal */}
                        {selectedOrder.customer_id_number && (
                          <p className="text-sm font-bold text-[#1c1a16] mt-1 bg-[#fcfbf9] inline-block px-2 py-0.5 rounded border border-[#ede8df]">
                            ID: {selectedOrder.customer_id_number}
                          </p>
                        )}

                        {selectedOrder.franchise_id && (
                          <p className="text-xs font-bold text-[#d2a356] mt-2 flex items-center gap-1"><Tag size={12}/> {selectedOrder.franchise_id}</p>
                        )}
                      </div>
                    </div>
                    
                    {/* Payment Card */}
                    <div className="p-4 border border-[#ede8df] bg-white rounded-2xl flex items-start gap-3 shadow-sm">
                      <CreditCard className="w-5 h-5 text-[#811816] mt-0.5 shrink-0" />
                      <div>
                        <p className="text-[0.65rem] font-bold text-[#a0998e] uppercase tracking-wider mb-1">Payment</p>
                        <p className="font-bold text-[#1c1a16] capitalize">{selectedOrder.payment_method === 'cod' ? 'Cash on Delivery' : 'M-Pesa STK'}</p>
                        {selectedOrder.mpesa_receipt && <p className="text-xs font-bold text-[#4a7c59] mt-1.5 bg-emerald-50 border border-emerald-100 px-2 py-0.5 rounded-md inline-block">Ref: {selectedOrder.mpesa_receipt}</p>}
                      </div>
                    </div>

                    {/* Delivery Logistics Card */}
                    <div className="p-4 border border-[#d2a356]/20 bg-[#fdf8ef] rounded-2xl flex items-start gap-3 md:col-span-2">
                      {selectedOrder.delivery_method === 'pickup' ? (
                        <MapPin className="w-5 h-5 text-[#d2a356] mt-0.5 shrink-0" />
                      ) : (
                        <Truck className="w-5 h-5 text-[#d2a356] mt-0.5 shrink-0" />
                      )}
                      <div className="w-full">
                        <p className="text-[0.65rem] font-bold text-[#a0998e] uppercase tracking-wider mb-2">
                          Logistics: {selectedOrder.delivery_method === 'pickup' ? 'Office Pickup' : 'Standard Delivery'}
                        </p>
                        
                        {selectedOrder.delivery_method === 'pickup' ? (
                          <p className="font-medium text-[#1c1a16] text-sm bg-white p-3 rounded-xl border border-[#ede8df]">
                            {getParsedAddress(selectedOrder.delivery_address).station || 'Harambee Ave Office'}
                          </p>
                        ) : (
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-2 gap-x-4 text-sm text-[#1c1a16] bg-white p-4 rounded-xl border border-[#ede8df] shadow-sm">
                            <p><span className="text-[#8a8070] font-medium block text-xs">County</span> <span className="capitalize font-bold">{getParsedAddress(selectedOrder.delivery_address).county || 'N/A'}</span></p>
                            <p><span className="text-[#8a8070] font-medium block text-xs">Estate/Town</span> <span className="font-bold">{getParsedAddress(selectedOrder.delivery_address).estate || 'N/A'}</span></p>
                            <p className="sm:col-span-2 pt-2 border-t border-[#ede8df]"><span className="text-[#8a8070] font-medium block text-xs">Specific Address</span> {getParsedAddress(selectedOrder.delivery_address).building || 'N/A'}</p>
                            {getParsedAddress(selectedOrder.delivery_address).landmarks && (
                              <p className="sm:col-span-2"><span className="text-[#8a8070] font-medium block text-xs">Landmarks</span> {getParsedAddress(selectedOrder.delivery_address).landmarks}</p>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Purchased Items List */}
                  <div>
                    <h3 className="font-bold text-[#1c1a16] mb-4 flex items-center gap-2 border-b border-[#ede8df] pb-2">
                      <Package className="w-5 h-5 text-[#8a8070]" /> Order Manifest
                    </h3>
                    <div className="space-y-3">
                      {selectedOrder.items && selectedOrder.items.map((item, index) => (
                        <div key={index} className="flex items-center justify-between p-3 border border-transparent hover:border-[#ede8df] hover:bg-white rounded-xl transition shadow-sm bg-white border-[#ede8df]/50">
                          <div>
                            <p className="font-bold text-[#1c1a16]">{item.name}</p>
                            <p className="text-sm text-[#8a8070]">Qty: {item.quantity} × KES {Number(item.price_at_time).toLocaleString()}</p>
                          </div>
                          <p className="font-bold text-[#1c1a16]">KES {(item.quantity * item.price_at_time).toLocaleString()}</p>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Total Bar */}
                  <div className="pt-6 border-t border-[#ede8df] flex items-center justify-between">
                    <p className="text-lg font-bold text-[#8a8070]">Total Charged</p>
                    <p className="text-3xl font-black text-[#811816]">KES {Number(selectedOrder.total_amount).toLocaleString()}</p>
                  </div>

                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminOrders;

import { useState, useEffect } from 'react';
import { Plus, Search, Edit, Trash2, X, Image as ImageIcon, Package } from 'lucide-react';
import api from '../../api';
import { useSettings } from '../../context/SettingsContext';


const AdminProducts = () => {
  const { globalDiscount } = useSettings();
  const [products, setProducts] = useState([]);

  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  
  // Modal & Form States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);
  
  const [formData, setFormData] = useState({
    name: '', price_kes: '', category_id: '', stock_quantity: '', description: '', full_description: '', ingredients_list: '',
    is_featured: false, custom_discount: ''
  });

  const [imageFile, setImageFile] = useState(null);

  const fetchProducts = async () => {
    setLoading(true);
    const response = await api.get('/products');
    if (response.data) setProducts(response.data);
    setLoading(false);
  };

  useEffect(() => { fetchProducts(); }, []);

  const uniqueCategories = Array.from(
    new Map(products.filter(p => p.category_id).map(p => [p.category_id, p.category_name])).entries()
  );

  const handleDelete = async (id, name) => {
    if (window.confirm(`Permanently delete ${name}?`)) {
      const response = await api.delete(`/products/${id}`);
      if (response.ok) setProducts(products.filter(p => p.id !== id));
    }
  };

  // --- OPEN MODAL FOR ADDING ---
  const handleAddNew = () => {
    setIsEditing(false);
    setEditId(null);
    setFormData({ name: '', price_kes: '', category_id: '', stock_quantity: '', description: '', full_description: '', ingredients_list: '', is_featured: false, custom_discount: '' });

    setImageFile(null);
    setIsModalOpen(true);
  };

  // --- OPEN MODAL FOR EDITING ---
  const handleEdit = (product) => {
    setIsEditing(true);
    setEditId(product.id);
    setFormData({
      name: product.name,
      price_kes: product.price_kes,
      category_id: product.category_id || '',
      stock_quantity: product.stock_quantity || 0,
      description: product.description || '',
      full_description: product.full_description || '',
      ingredients_list: product.ingredients_list || '',
      is_featured: product.is_featured || false,
      custom_discount: product.custom_discount || ''
    });

    setImageFile(null); // Reset file input
    setIsModalOpen(true);
  };

  // --- SUBMIT FORM (Handles both Add and Edit) ---
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // We MUST use FormData to send files to the backend
    const data = new FormData();
    data.append('name', formData.name);
    data.append('price_kes', formData.price_kes);
    data.append('category_id', formData.category_id);
    data.append('stock_quantity', formData.stock_quantity);
    data.append('description', formData.description);
    data.append('full_description', formData.full_description);
    data.append('ingredients_list', formData.ingredients_list);
    data.append('is_featured', formData.is_featured);
    data.append('custom_discount', formData.custom_discount);

    
    if (imageFile) {
      data.append('image', imageFile); // Attach the actual file!
    }

    let response;
    if (isEditing) {
      response = await api.sendForm(`/products/${editId}`, 'PUT', data);
    } else {
      response = await api.sendForm('/products', 'POST', data);
    }

    if (response.ok) {
      fetchProducts();
      setIsModalOpen(false);
    } else {
      alert("Error saving product.");
    }
  };

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()));

  return (
    <div className="p-8 lg:p-12 relative bg-[#fcfbf9] min-h-screen font-dm">
      <div className="flex flex-col items-start justify-between gap-4 mb-10 sm:flex-row sm:items-center">
        <div>
          <h1 className="font-garamond text-3xl font-medium text-stone-900">Products ({products.length})</h1>
          <p className="mt-1 text-sm text-stone-500">Manage your apothecary inventory and pricing.</p>
        </div>
        <button onClick={handleAddNew} className="flex items-center px-5 py-2.5 text-sm font-medium text-[#f7f4ef] transition-all bg-[#811816] rounded-xl hover:bg-[#6a1210] shadow-sm hover:shadow-md duration-300">
          <Plus className="w-4 h-4 mr-2" /> Add New Product
        </button>
      </div>

      <div className="flex items-center justify-between p-4 mb-6 bg-white border shadow-sm border-stone-200 rounded-2xl">
        <div className="relative w-full max-w-md">
          <Search className="absolute w-4 h-4 text-stone-400 left-3 top-3" />
          <input 
            type="text" 
            placeholder="Search catalog..." 
            value={searchQuery} 
            onChange={(e) => setSearchQuery(e.target.value)} 
            className="w-full py-2.5 pl-10 pr-4 text-sm border rounded-xl bg-stone-50 border-stone-200 focus:outline-none focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 transition-all" 
          />
        </div>
      </div>

      <div className="overflow-hidden bg-white border shadow-sm border-stone-200 rounded-2xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="text-sm bg-stone-50 text-stone-500 border-b border-stone-200">
              <tr>
                <th className="px-6 py-4 font-medium">Image</th>
                <th className="px-6 py-4 font-medium">Product Name</th>
                <th className="px-6 py-4 font-medium">Price (KES)</th>
                <th className="px-6 py-4 font-medium">Stock</th>
                <th className="px-6 py-4 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="text-sm divide-y divide-stone-100">
              {loading ? <tr><td colSpan="5" className="py-10 text-center text-stone-500">Loading live database...</td></tr> : 
                filteredProducts.map((product) => (
                  <tr key={product.id} className="transition-colors hover:bg-[#fcf5f5]/50">
                    <td className="px-6 py-4">
                      {/* Show the uploaded image, or a placeholder icon if none exists */}
                      {product.image_url ? (
                        <img src={api.getImageUrl(product.image_url)} alt={product.name} className="w-12 h-12 object-cover rounded-xl border border-stone-200 mix-blend-multiply" />
                      ) : (
                        <div className="w-12 h-12 bg-stone-100 rounded-xl flex items-center justify-center border border-stone-200 text-stone-400"><ImageIcon className="w-5 h-5"/></div>
                      )}
                    </td>
                    <td className="px-6 py-4 font-bold text-stone-900">{product.name}</td>
                    <td className="px-6 py-4 font-medium text-stone-900">{Number(product.price_kes).toLocaleString()}</td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-bold border ${product.stock_quantity > 0 ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                        {product.stock_quantity > 0 ? `${product.stock_quantity} in stock` : 'Out of Stock'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      {/* EDIT BUTTON */}
                      <button onClick={() => handleEdit(product)} className="p-2 mr-2 transition-colors rounded-lg text-stone-400 hover:text-[#d2a356] hover:bg-stone-50">
                        <Edit className="w-5 h-5" />
                      </button>
                      <button onClick={() => handleDelete(product.id, product.name)} className="p-2 transition-colors rounded-lg text-stone-400 hover:text-red-600 hover:bg-red-50">
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))
              }
            </tbody>
          </table>
        </div>
      </div>

      {/* --- ADD/EDIT PRODUCT MODAL --- */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-stone-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
            <div className="flex items-center justify-between px-6 py-4 border-b border-stone-100 bg-stone-50">
              <h2 className="text-xl font-bold text-stone-900 flex items-center gap-2">
                <Package className="w-5 h-5 text-[#811816]" />
                {isEditing ? 'Edit Product' : 'Add New Product'}
              </h2>
              <button onClick={() => setIsModalOpen(false)} className="p-2 text-stone-400 hover:text-stone-800 rounded-full hover:bg-stone-200 transition"><X className="w-6 h-6"/></button>
            </div>
            
            <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto custom-scrollbar">
              
              {/* IMAGE UPLOAD FIELD */}
              <div>
                <label className="block text-sm font-bold text-stone-700 mb-2">Product Image</label>
                <div className="flex items-center gap-4">
                  <input 
                    type="file" 
                    accept="image/*"
                    onChange={e => setImageFile(e.target.files[0])}
                    className="w-full text-sm text-stone-500 file:mr-4 file:py-2.5 file:px-4 file:rounded-xl file:border-0 file:font-medium file:bg-[#fcf5f5] file:text-[#811816] hover:file:bg-[#811816]/10 transition cursor-pointer" 
                  />
                </div>
                {isEditing && <p className="text-xs text-stone-400 mt-2">Leave blank to keep current image.</p>}
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Product Name</label>
                <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-stone-700 mb-1.5">Price (KES)</label>
                  <input required type="number" value={formData.price_kes} onChange={e => setFormData({...formData, price_kes: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-stone-700 mb-1.5">Stock Quantity</label>
                  <input required type="number" value={formData.stock_quantity} onChange={e => setFormData({...formData, stock_quantity: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all" />
                </div>
              </div>

              {/* Admin Pricing Strategy UI */}
              <div className="flex flex-col gap-3 p-5 bg-[#fcfbf9] border border-[#ede8df] rounded-2xl">
                <label className="font-dm text-sm font-bold text-[#1c1a16] flex items-center gap-2">
                  B2B Pricing Strategy
                </label>
                
                <select 
                  value={
                    formData.custom_discount === null || formData.custom_discount === '' ? 'global' : 
                    formData.custom_discount === 0 || formData.custom_discount === '0' || formData.custom_discount === 0 ? 'none' : 'custom'
                  }
                  onChange={(e) => {
                    const val = e.target.value;
                    if (val === 'global') setFormData({ ...formData, custom_discount: '' });
                    if (val === 'none') setFormData({ ...formData, custom_discount: 0 });
                    if (val === 'custom') setFormData({ ...formData, custom_discount: 15 }); // default starting point
                  }}
                  className="w-full border border-[#ede8df] rounded-xl p-3 bg-white font-dm focus:border-[#d2a356] outline-none"
                >
                  <option value="global">Use Global Discount (Currently {globalDiscount}%)</option>
                  <option value="none">No Discount (Sell at Strict Retail Price)</option>
                  <option value="custom">Override with Custom Discount</option>
                </select>

                {/* Only show the number input if they select "Custom" */}
                {formData.custom_discount !== null && formData.custom_discount !== '' && formData.custom_discount !== 0 && formData.custom_discount !== '0' && (
                  <div className="relative mt-2 animate-in fade-in zoom-in-95 duration-300">
                    <input 
                      type="number" 
                      value={formData.custom_discount}
                      onChange={(e) => setFormData({...formData, custom_discount: Number(e.target.value)})}
                      className="w-full border-2 border-[#d2a356] rounded-xl p-3 focus:ring-4 ring-[#d2a356]/20 outline-none font-dm font-medium text-[#811816]"
                      min="1"
                      max="99"
                    />
                    <span className="absolute right-4 top-1/2 -translate-y-1/2 text-[#811816] font-bold">% OFF</span>
                  </div>
                )}
              </div>



              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Category</label>
                <select required value={formData.category_id} onChange={e => setFormData({...formData, category_id: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all">
                  <option value="" disabled>Select a category...</option>
                  {uniqueCategories.map(([id, name]) => <option key={id} value={id}>{name}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Brief Description</label>
                <textarea rows="2" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all resize-none"></textarea>
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Full Description</label>
                <textarea rows="3" value={formData.full_description} onChange={e => setFormData({...formData, full_description: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all resize-none"></textarea>
              </div>

              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1.5">Ingredients List</label>
                <textarea rows="2" value={formData.ingredients_list} onChange={e => setFormData({...formData, ingredients_list: e.target.value})} className="w-full px-4 py-2.5 border border-stone-200 rounded-xl focus:border-[#d2a356] focus:ring-[3px] focus:ring-[#d2a356]/20 outline-none transition-all resize-none"></textarea>
              </div>

              <div className="flex items-center gap-3 pt-4 border-t border-stone-100">
                <label className="flex items-center cursor-pointer group">
                  <input 
                    type="checkbox" 
                    checked={formData.is_featured} 
                    onChange={e => setFormData({...formData, is_featured: e.target.checked})} 
                    className="w-5 h-5 rounded border-stone-300 text-[#811816] focus:ring-[#811816] accent-[#811816] cursor-pointer" 
                  />
                  <span className="ml-2.5 font-bold text-stone-700 group-hover:text-stone-900 transition-colors">Feature this product in Storefront Pop-up</span>
                </label>
              </div>

              <div className="pt-5 flex justify-end gap-3 pb-2 border-t border-stone-100">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-5 py-2.5 text-sm font-medium text-stone-600 bg-stone-100 hover:bg-stone-200 rounded-xl transition-colors">Cancel</button>
                <button type="submit" className="px-5 py-2.5 text-sm font-medium text-[#f7f4ef] bg-[#811816] hover:bg-[#6a1210] rounded-xl transition-all duration-300 shadow-sm hover:shadow-md">
                  {isEditing ? 'Save Changes' : 'Upload Product'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminProducts;
